              <button disabled={!carousel} onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="flex-1 py-4 bg-emerald-500 hover:bg-emerald-400 disabled:opacity-30 text-black font-black rounded-xl text-[10px] uppercase shadow-lg flex items-center justify-center gap-3"><Download size={16} /> Exportar</button>
