                 </div>
                 <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 hover:text-white transition-all"><ChevronRight size={20}/></button>
              </div>
            )}
          </main>
        </div>
      )}

      {showSaveModal && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center bg-black/90 backdrop-blur-xl animate-in fade-in" onClick={() => setShowSaveModal(false)}>
          <div className="w-full max-w-md bg-zinc-900 border border-white/10 p-8 rounded-[40px] space-y-6 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
             <h2 className="text-xl font-black text-white uppercase italic">Salvar Projeto</h2>
