             <input type="text" placeholder="Cliente" value={saveFormData.client} onChange={e => setSaveFormData({ ...saveFormData, client: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-6 text-white font-bold outline-none" />
             <button onClick={handleSaveProject} className="w-full py-5 bg-emerald-500 text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3"><Save size={18} /> Salvar Agora</button>
          </div>
