      {isExporting && (
        <div className="fixed inset-0 z-[600] flex flex-col items-center justify-center bg-black/95 backdrop-blur-3xl animate-in fade-in">
           <Loader2 size={64} className="animate-spin text-emerald-500 mb-8" />
