    <div className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden">
      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in duration-500 shadow-2xl border border-white/10 ${toast.type === 'success' ? 'bg-emerald-500 text-black' : 'bg-red-500 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={28} /> : <AlertCircle size={28} />}
          <span className="text-[16px] font-black uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

