import React from 'react';
import { Block, Theme } from '../types.ts';
import { TitleRenderer } from "./blocks/TitleRenderer.tsx";
import { ParagraphRenderer } from "./blocks/ParagraphRenderer.tsx";
import { ListRenderer } from "./blocks/ListRenderer.tsx";
import { SpacerRenderer } from "./blocks/SpacerRenderer.tsx";
import { ImageRenderer } from "./blocks/ImageRenderer.tsx";
import { CardRenderer } from "./blocks/CardRenderer.tsx";
import { BadgeRenderer } from "./blocks/BadgeRenderer.tsx";
import { BoxRenderer } from "./blocks/BoxRenderer.tsx";

export function renderBlock(
  block: Block, 
  theme: Theme, 
  onEditIcon?: (block: Block, index: number) => void, 
  isGridMember?: boolean, 
  indexInGrid?: number, 
  globalIndex?: number
) {
  const wrapperStyle: React.CSSProperties = {
    position: 'relative',
    width: '100%',
    display: isGridMember ? 'flex' : 'block',
    flexDirection: isGridMember ? 'column' : undefined,
  };

  const blockIdx = globalIndex ?? 0;

  const content = (() => {
    switch (block.type) {
      case "TITLE":
        return <TitleRenderer block={block} theme={theme} />;
      case "PARAGRAPH":
        return <ParagraphRenderer block={block} theme={theme} />;
      case "LIST":
        return <ListRenderer block={block} theme={theme} />;
      case "SPACER":
        return <SpacerRenderer block={block} />;
      case "IMAGE":
        return <ImageRenderer block={block} />;
      case "CARD":
        return <CardRenderer block={block} theme={theme} onEditIcon={(b) => onEditIcon?.(b, blockIdx)} />;
      case "BADGE":
        return <BadgeRenderer block={block} theme={theme} />;
      case "BOX":
        return <BoxRenderer block={block} theme={theme} isGridMember={isGridMember} indexInGrid={indexInGrid} onEditIcon={(b) => onEditIcon?.(b, blockIdx)} />;
      default:
        return null;
    }
  })();

  return (
    <div 
      style={wrapperStyle} 
      data-block-index={globalIndex} 
      className="render-block-wrapper"
    >
      {content}
    </div>
  );
}

import React, { useMemo } from 'react'
import { ValidatedSlide } from '../template-dsl/schema.ts'
import { TOKENS } from '../design-tokens/tokens.ts'
import { renderBlock } from './renderBlock.tsx'
import { templateRegistry } from '../domain/templates/TemplateRegistry.ts'
import { Image as ImageIcon, Box, User, Layers, Package } from 'lucide-react'
import { Block } from '../types.ts'

export const SlideCanvas: React.FC<{ 
  slide: ValidatedSlide, 
  index: number, 
  canvasRef: React.RefObject<HTMLDivElement>,
  onEditIcon?: (block: Block, index: number) => void 
}> = ({ slide, index, canvasRef, onEditIcon }) => {
  const isLight = slide.options?.theme === 'light'
  const templateDef = templateRegistry.get(slide.template)

  const theme = useMemo(() => {
    const baseBackground = isLight ? '#F2F2F2' : '#0D0D0D'
    const baseTextPrimary = isLight ? '#000000' : '#FFFFFF'
    const baseTextSecondary = isLight ? '#333333' : 'rgba(255, 255, 255, 0.9)'

    return {
      ...TOKENS,
      colors: {
        ...TOKENS.colors,
        background: slide.options?.background || baseBackground,
        textPrimary: slide.options?.text || baseTextPrimary,
        textSecondary: slide.options?.text ? `${slide.options.text}cc` : baseTextSecondary,
        accent: slide.options?.accent || TOKENS.colors.accent,
        highlight: slide.options?.accent || TOKENS.colors.highlight,
        cardBg: slide.options?.cardBg || slide.options?.accent || TOKENS.colors.accent,
        cardTextColor: slide.options?.cardTextColor,
        cardOpacity: slide.options?.cardOpacity !== undefined ? slide.options.cardOpacity : 1,
        hlBgColor: slide.options?.hlBgColor || slide.options?.accent || TOKENS.colors.accent,
        hlTextColor: slide.options?.hlTextColor || '#000000',
      }
    }
  }, [isLight, slide.options?.background, slide.options?.accent, slide.options?.text, slide.options?.cardBg, slide.options?.cardTextColor, slide.options?.cardOpacity, slide.options?.hlBgColor, slide.options?.hlTextColor])

  if (!templateDef) return <div ref={canvasRef} className="w-[1080px] h-[1350px] bg-red-900 flex items-center justify-center text-white font-bold">ERROR: TEMPLATE NOT FOUND</div>

  const imageConfig = slide.image;
  const texture = slide.options?.texture;
  const fx = slide.options?.postFX;

  const blockGap = slide.options?.blockGap !== undefined ? slide.options.blockGap : 16;
  const sectionGap = slide.options?.sectionGap !== undefined ? slide.options.sectionGap : 48;
  const padding = slide.options?.padding !== undefined ? slide.options.padding : 80;

  const renderImage = (className: string, fit: 'cover' | 'contain' = 'cover', extraStyle: React.CSSProperties = {}) => {
    if (!imageConfig?.url) return null;

    const scale = imageConfig.scale ?? 1;
    const x = imageConfig.x ?? 0;
    const y = imageConfig.y ?? 0;
    const opacity = imageConfig.backgroundOpacity ?? 1;

    return (
      <img 
        src={imageConfig.url} 
        className={`${className} ${fit === 'cover' ? 'object-cover' : 'object-contain'} transition-all duration-300 ease-out`}
        style={{ 
          objectPosition: `calc(50% + ${x}px) calc(50% + ${y}px)`,
          transform: `scale(${scale})`,
          transformOrigin: 'center',
          opacity: opacity,
          ...extraStyle
        }}
        alt="" 
      />
    );
  };

  const renderBlocks = () => (
    <div 
      className="w-full relative z-30 flex flex-col"
      style={{ gap: `${blockGap}px` }}
    >
      {slide.blocks.map((b, i) => <React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, false, 0, i)}</React.Fragment>)}
    </div>
  );

  const renderFXOverlays = () => {
    const overlays: React.ReactNode[] = [];
    const fxId = `fx-${index}`;

    if (fx?.lightingIntensity && fx.lightingIntensity > 0) {
      overlays.push(
        <div 
          key="fx-lighting"
          className="absolute inset-0 pointer-events-none z-[42]"
          style={{
            background: `radial-gradient(circle at 30% 20%, rgba(255,255,255,${fx.lightingIntensity * 0.15}), transparent 80%)`,
            mixBlendMode: 'screen'
          }}
        />
      );
    }

    if (fx?.vignette && fx.vignette > 0) {
      overlays.push(
        <div 
          key="fx-vignette"
          className="absolute inset-0 pointer-events-none z-[48]"
          style={{
            background: `radial-gradient(circle, transparent 40%, rgba(0,0,0,${fx.vignette * 0.6}) 100%)`,
            mixBlendMode: 'multiply'
          }}
        />
      );
    }

    if (fx?.noiseAmount && fx.noiseAmount > 0) {
      overlays.push(
        <div 
          key="fx-noise"
          className="absolute inset-0 pointer-events-none z-[49]"
          style={{
            opacity: fx.noiseAmount,
            mixBlendMode: (fx.noiseMode as any) || 'multiply'
          }}
        >
          <svg width="100%" height="100%">
            <filter id={`${fxId}-noise`}>
              <feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch" />
              <feColorMatrix type="saturate" values="0" />
            </filter>
            <rect width="100%" height="100%" filter={`url(#${fxId}-noise)`} fill="transparent" />
          </svg>
        </div>
      );
    }

    return overlays;
  };

  const renderLayout = () => {
    const canvasPadding = `${padding}px`;
    const imageBoxStyle: React.CSSProperties = {
      border: imageConfig?.borderWidth ? `${imageConfig.borderWidth}px solid ${imageConfig.borderColor || '#FFFFFF'}` : 'none',
      boxShadow: imageConfig?.hasShadow ? `0 40px 120px -20px rgba(0,0,0,0.8), 0 0 100px ${imageConfig.borderColor || theme.colors.accent}40` : 'none',
    };

    const clarityIntensity = fx?.clarity || 0;
    const contentFilter = clarityIntensity > 0 
      ? `contrast(${1 + clarityIntensity * 0.25}) saturate(${1 + clarityIntensity * 0.15}) brightness(${1 - clarityIntensity * 0.05})`
      : 'none';

    const renderLayoutInternal = () => {
      if (templateDef.name === 'CARD_BOX') {
        const boxBlocks = slide.blocks.filter(b => b.type === 'BOX');
        const otherBlocks = slide.blocks.filter(b => b.type !== 'BOX');
        return (
          <div className="relative h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}>
            {otherBlocks.length > 0 && (
              <div className="mb-12 w-full flex flex-col gap-8">
                 {otherBlocks.map((b, i) => (
                   <React.Fragment key={i}>
                     {renderBlock(b, theme, onEditIcon, false, 0, slide.blocks.indexOf(b))}
                   </React.Fragment>
                 ))}
              </div>
            )}
            <div className="grid grid-cols-2 gap-10 w-full">
              {boxBlocks.map((b, i) => (
                <React.Fragment key={i}>
                  {renderBlock(b, theme, onEditIcon, true, i, slide.blocks.indexOf(b))}
                </React.Fragment>
              ))}
            </div>
          </div>
        );
      }

      if (imageConfig?.type === 'IMAGE_GLASS_CARD') {
        const isDarkBox = imageConfig.boxOverlay === 'dark';
        return (
          <div className="relative h-full w-full">
            <div className="absolute inset-0 overflow-hidden z-0 bg-zinc-900">
              {imageConfig.url ? renderImage("w-full h-full", "cover") : null}
            </div>
            <div className="relative z-10 h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}>
              <div style={imageBoxStyle} className={`w-full max-w-[840px] backdrop-blur-[20px] saturate-[160%] p-20 rounded-[80px] border border-white/30 ${isDarkBox ? 'bg-black/60' : 'bg-white/5'}`}>
                 {renderBlocks()}
              </div>
            </div>
          </div>
        );
      }

      if (imageConfig?.type === 'IMAGE_BOX') {
          const isRight = imageConfig.position !== 'left';
          const boxWidth = imageConfig.width || 480;
          return (
            <div className={`relative h-full w-full flex items-center ${isRight ? 'flex-row' : 'flex-row-reverse'}`} style={{ padding: canvasPadding, gap: `${sectionGap}px` }}>
              <div className="flex-1 min-w-0 z-20">
                 {renderBlocks()}
              </div>
              <div style={{ width: `${boxWidth}px`, ...imageBoxStyle }} className="h-[850px] relative shrink-0 z-10 bg-zinc-800 rounded-[50px] overflow-hidden border-4 border-white/10">
                  {imageConfig.url ? renderImage("w-full h-full", "cover") : null}
              </div>
            </div>
          );
      }

      const isFullBg = imageConfig?.type === 'IMAGE_BACKGROUND' || imageConfig?.type === 'IMAGE_SELECT';
      return (
        <div className="relative h-full w-full">
          {isFullBg && (
              <div style={imageBoxStyle} className="absolute inset-0 overflow-hidden z-0">
                  {imageConfig.url ? renderImage("w-full h-full", "cover") : null}
                  {imageConfig.overlay === 'dark' && <div className="absolute inset-0 bg-black/60" />}
              </div>
          )}
          <div className="relative z-10 h-full w-full flex flex-col justify-center items-start" style={{ padding: canvasPadding }}>
              <div className="w-full max-w-[840px] mx-auto flex flex-col justify-center min-h-0">
                  {renderBlocks()}
              </div>
          </div>
        </div>
      );
    }

    return (
      <div style={{ filter: contentFilter }} className="h-full w-full">
        {renderLayoutInternal()}
      </div>
    );
  }

  return (
    <div
      ref={canvasRef}
      style={{ backgroundColor: theme.colors.background, color: theme.colors.textPrimary, fontFamily: theme.typography.fontFamily }}
      className="relative w-[1080px] h-[1350px] flex flex-col shadow-2xl overflow-hidden shrink-0 select-auto cursor-text"
    >
      {renderLayout()}
      {renderFXOverlays()}
    </div>
  )
}

