    } catch (err) {
      const local = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
      localStorage.setItem(STORAGE_KEYS.PALETTES, JSON.stringify(local.filter((p: any) => p.id !== id)));
      loadData();
    } finally { setIsSyncing(false); }
  };

  const handleTemplateSelect = (tpl: TemplateDefinition) => {
    const updates = [{ path: ['template'], value: tpl.name }];
    switch(tpl.name) {
      case 'PREMIUM_GLASS': updates.push({ path: ['image', 'type'], value: 'IMAGE_GLASS_CARD' }, { path: ['image', 'boxOverlay'], value: 'dark' }); break;
      case 'SPLIT_EDITORIAL': updates.push({ path: ['image', 'type'], value: 'IMAGE_SPLIT_HALF' }, { path: ['image', 'position'], value: 'right' }); break;
      case 'PROFILE_FOCUS': updates.push({ path: ['image', 'type'], value: 'FOCUS_SUBJECT' }, { path: ['image', 'position'], value: 'right' }); break;
      case 'IMAGE_SIDEBAR': updates.push({ path: ['image', 'type'], value: 'IMAGE_BOX' }, { path: ['image', 'position'], value: 'right' }, { path: ['image', 'width'], value: 400 }); break;
      default: break;
    }
    updateSlideProperties(updates); showToast(`Template aplicado!`);
  };

  const clients = useMemo(() => Array.from(new Set(projects.map(p => p.client_name))).sort(), [projects]);
  const filteredProjects = useMemo(() => projects.filter(p => {
    const search = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return search && (selectedClientFilter ? p.client_name === selectedClientFilter : true);
  }), [projects, searchQuery, selectedClientFilter]);

  return (
    <div className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden">
      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in shadow-[0_30px_90px_rgba(0,0,0,0.6)] backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-emerald-500/95 text-black' : 'bg-red-500/95 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={28} strokeWidth={3} /> : <AlertCircle size={28} strokeWidth={3} />}
          <span className="text-[16px] font-black uppercase tracking-[0.1em]">{toast.message}</span>
        </div>
      )}

      <input type="file" ref={importInputRef} onChange={handleImportProject} accept=".json" className="hidden" />

      {toolbarState && <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={updateSlideProperties} />}

      {showExportModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl" onClick={() => setShowExportModal(false)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Exportar Carrossel</h2>
                 <button onClick={() => setShowExportModal(false)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="grid grid-cols-4 gap-4 max-h-[400px] overflow-y-auto custom-scrollbar p-1">
                 {carousel?.slides.map((s, idx) => (
                    <button key={idx} onClick={() => {
                        const next = new Set(selectedSlidesToExport);
                        if (next.has(idx)) next.delete(idx); else next.add(idx);
                        setSelectedSlidesToExport(next);
                      }} className={`relative aspect-[4/5] rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-3 overflow-hidden ${selectedSlidesToExport.has(idx) ? 'border-emerald-500 bg-emerald-500/10' : 'border-white/5 bg-black/40 hover:border-white/20'}`}>
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center ${selectedSlidesToExport.has(idx) ? 'bg-emerald-500 text-black' : 'bg-zinc-800 text-zinc-500'}`}><span className="font-black text-xs">{idx + 1}</span></div>
                       <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest truncate px-2 w-full">{s.template.replace(/_/g, ' ')}</p>
                    </button>
                 ))}
              </div>
              <div className="flex gap-4 pt-4 border-t border-white/5">
                 <button onClick={() => setSelectedSlidesToExport(new Set())} className="px-6 py-5 text-[10px] font-black text-zinc-500 uppercase tracking-widest">Limpar</button>
                 <button onClick={() => setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i)))} className="px-6 py-5 text-[10px] font-black text-emerald-500 uppercase tracking-widest">Todos</button>
                 <button onClick={startBatchExport} disabled={selectedSlidesToExport.size === 0} className="flex-1 py-5 bg-emerald-500 hover:bg-emerald-400 disabled:opacity-30 text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3"><Download size={18} strokeWidth={3} /> Gerar Slides</button>
              </div>
           </div>
        </div>
      )}

      {editingIconBlock && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl" onClick={() => setEditingIconBlock(null)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Escolher Ícone</h2>
              <div className="grid grid-cols-4 sm:grid-cols-6 gap-4 p-1">
                 {ICON_LIBRARY_PRESETS.map(item => (
                    <button key={item.id} onClick={() => { updateSlideProperty(['blocks', editingIconBlock.index, 'options', 'icon'], item.id); setEditingIconBlock(null); }} className={`flex flex-col items-center justify-center gap-3 p-5 rounded-3xl border-2 transition-all group ${editingIconBlock.block.options?.icon === item.id ? 'border-emerald-500 bg-emerald-500/10 text-emerald-400' : 'border-white/5 bg-black/40 hover:border-emerald-500/50'}`}>
                       <item.icon size={32} strokeWidth={1.5} className="group-hover:scale-110" />
                       <span className="text-[8px] font-black uppercase tracking-tighter text-zinc-600">{item.label}</span>
                    </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      {isCreatingPalette && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl" onClick={() => setIsCreatingPalette(false)}>
           <div className="w-full max-w-xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Nova Identidade</h2>
              <div className="space-y-8">
                <input type="text" value={newPaletteData.name} onChange={(e) => setNewPaletteData({ ...newPaletteData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-5 px-6 text-white font-bold outline-none" placeholder="Ex: Apple Minimal" />
                <div className="grid grid-cols-5 gap-4">
                   {['Fundo', 'Texto', 'Acento', 'Destaque', 'Cards'].map((label, idx) => (
                     <div key={idx} className="flex flex-col items-center gap-3">
                        <span className="text-[9px] font-black uppercase text-zinc-600">{label}</span>
                        <div className="relative w-16 h-16 rounded-full overflow-hidden border-2 border-white/10">
                           <input type="color" value={newPaletteData.colors[idx]} onChange={(e) => {
                                const next = [...newPaletteData.colors]; next[idx] = e.target.value;
                                setNewPaletteData({ ...newPaletteData, colors: next });
                              }} className="absolute inset-[-10px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none bg-transparent" />
                        </div>
                     </div>
                   ))}
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                 <button onClick={() => setIsCreatingPalette(false)} className="flex-1 py-5 text-[11px] font-black text-zinc-500 uppercase">Cancelar</button>
                 <button onClick={handleCreatePalette} disabled={!newPaletteData.name.trim()} className="flex-[2] py-5 bg-emerald-500 hover:bg-emerald-400 text-black font-black uppercase rounded-2xl shadow-2xl">Criar Paleta</button>
              </div>
           </div>
        </div>
      )}

      {isExporting && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center bg-black/80 backdrop-blur-3xl">
           <div className="w-full max-md space-y-10 text-center px-10">
              <Loader2 size={64} className="animate-spin text-emerald-500 mx-auto" strokeWidth={3} />
              <div className="space-y-4">
                 <h2 className="text-2xl font-black text-white uppercase tracking-tighter animate-pulse">{exportStatus}</h2>
                 <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden">
                    <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${exportProgress}%` }} />
                 </div>
              </div>
           </div>
        </div>
      )}

      {showSaveModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl" onClick={() => setShowSaveModal(false)}>
           <div className="w-full max-w-md bg-zinc-900 border border-white/10 rounded-[32px] p-8 space-y-8 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <h2 className="text-lg font-black text-white uppercase tracking-tight">Salvar Projeto</h2>
              <div className="space-y-6">
                <input type="text" value={saveFormData.name} onChange={(e) => setSaveFormData({ ...saveFormData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none" placeholder="Ex: Campanha Verão" />
                <input type="text" value={saveFormData.client} onChange={(e) => setSaveFormData({ ...saveFormData, client: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none" placeholder="Ex: Coca-Cola" />
              </div>
              <button type="button" onClick={handleSaveProject} disabled={isSyncing || !saveFormData.name.trim()} className="w-full py-5 bg-emerald-500 text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3">
                {isSyncing ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                {isSyncing ? "Salvando..." : "Salvar Agora"}
              </button>
           </div>
        </div>
      )}

      {view === 'DASHBOARD' ? (
        <div className="min-h-screen w-full bg-[#050507] text-white flex flex-col overflow-y-auto custom-scrollbar">
          <header className="px-10 py-8 flex items-center justify-between border-b border-white/5 sticky top-0 bg-[#050507]/80 backdrop-blur-xl z-50">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center shadow-2xl shadow-emerald-500/20"><LayoutTemplate size={20} className="text-black" /></div>
              <h1 className="text-xl font-black italic uppercase tracking-tighter">Insta<span className="text-emerald-500">Render</span></h1>
            </div>
            <div className="flex-1 max-w-xl mx-20 relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-600" size={18} />
              <input type="text" placeholder="Pesquisar projetos..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 pl-12 pr-4 text-[13px] font-bold text-white outline-none focus:border-emerald-500/50" />
            </div>
            <div className="flex gap-4">
              <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 px-6 py-3 bg-white/5 border border-white/10 text-white font-black uppercase text-[11px] rounded-xl"><Upload size={16} /> Subir</button>
              <button onClick={handleNewProject} className="flex items-center gap-2 px-6 py-3 bg-emerald-500 text-black font-black uppercase text-[11px] rounded-xl shadow-xl shadow-emerald-500/10"><Plus size={16} strokeWidth={3} /> Criar Projeto</button>
            </div>
          </header>
          <main className="p-10 max-w-[1400px] mx-auto w-full">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProjects.map(proj => (
                  <div key={proj.id} className="h-80 bg-zinc-900/40 border border-white/5 rounded-[32px] p-0 flex flex-col transition-all cursor-pointer group overflow-hidden">
                      <div onClick={() => handleOpenProject(proj)} className="flex-1 p-8 space-y-4 hover:bg-white/5 transition-colors">
                        <div className="w-12 h-12 bg-black/40 rounded-2xl flex items-center justify-center border border-white/5 group-hover:border-emerald-500/20"><Library size={20} className="text-zinc-600 group-hover:text-emerald-500" /></div>
                        <h3 className="text-base font-black text-white truncate">{proj.name}</h3>
                        <p className="text-[9px] font-black uppercase opacity-50">{proj.slideCount} Slides • {new Date(proj.updatedAt).toLocaleDateString()}</p>
                      </div>
                      <div className="h-16 px-6 border-t border-white/5 bg-black/20 flex items-center justify-between">
                         <button onClick={(e) => handleDeleteProject(proj.id, e)} className="p-2 text-red-400 hover:text-white transition-all"><Trash2 size={16} /></button>
                         <ChevronRightSmall size={14} className="text-emerald-500 opacity-40 group-hover:opacity-100 transition-opacity" />
                      </div>
                  </div>
                ))}
            </div>
          </main>
        </div>
      ) : (
        <div className="flex h-screen w-full">
          <aside className="w-[440px] border-r border-white/5 flex flex-col bg-zinc-900/50 backdrop-blur-2xl z-20 shrink-0">
            <header className="p-5 border-b border-white/5 space-y-4">
              <div className="flex items-center justify-between">
                <button onClick={() => setView('DASHBOARD')} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-zinc-500 hover:text-white transition-all"><Home size={18} /></button>
                <h1 className="text-sm font-black text-white italic uppercase tracking-tighter">InstaRender</h1>
                <button onClick={() => setShowSaveModal(true)} className="p-2 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 rounded-lg"><Save size={18} /></button>
              </div>
              <nav className="flex gap-1 p-1 bg-black/40 rounded-xl">
                {[
                  { id: 'TEMPLATES', label: 'Tpl', icon: Library },
                  { id: 'DESIGN', label: 'Marca', icon: Palette },
                  { id: 'FX', label: 'FX', icon: Sparkles },
                  { id: 'ASSETS', label: 'Assets', icon: ImageIcon },
                  { id: 'JSON', label: 'JSON', icon: FileJson },
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 rounded-lg text-[9px] font-black uppercase tracking-wider transition-all ${activeTab === tab.id ? 'bg-zinc-800 text-emerald-400' : 'text-zinc-500 hover:text-zinc-300'}`}>
                    <tab.icon size={14} /> {tab.label}
                  </button>
                ))}
              </nav>
            </header>
            <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-6">
              {activeTab === 'DESIGN' && (
                <div className="space-y-10 animate-in fade-in slide-in-from-left-4 duration-300">
                  <div className="flex items-center justify-between px-1">
                    <h3 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Brand Palettes</h3>
                    <button onClick={() => setIsCreatingPalette(true)} className="text-[8px] font-black text-emerald-400 uppercase bg-emerald-500/10 px-2.5 py-1.5 rounded-lg border border-emerald-500/20">New Palette</button>
                  </div>
                  <div className="grid grid-cols-1 gap-3">
                    {brandPresets.map(preset => (
                      <button key={preset.id} onClick={() => handleApplyPalettePreset(preset)} className={`w-full p-4 border rounded-2xl transition-all flex items-center justify-between group ${activePaletteId === preset.id ? 'bg-emerald-500/10 border-emerald-500' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                        <div className="flex items-center gap-4">
                          <div className="flex -space-x-2">{preset.colors.slice(0, 4).map((c: string, i: number) => (<div key={i} className="w-5 h-5 rounded-full border-2 border-zinc-900 shadow-sm" style={{ backgroundColor: c }} />))}</div>
                          <span className={`text-[11px] font-black uppercase ${activePaletteId === preset.id ? 'text-emerald-400' : 'text-zinc-400'}`}>{preset.name}</span>
                        </div>
                        {!DEFAULT_BRAND_PRESETS.some(d => d.id === preset.id) && (<button onClick={(e) => handleDeletePalette(e, preset.id)} className="p-2 opacity-0 group-hover:opacity-100 hover:text-red-400 text-zinc-600"><Trash2 size={12} /></button>)}
                      </button>
                    ))}
                  </div>
                  <section className="space-y-8 border-t border-white/5 pt-6">
                     <TransformControl label="Proximidade (Block Gap)" value={currentSlide?.options?.blockGap ?? 16} min={0} max={160} step={2} onChange={(v) => updateSlideProperty(['options', 'blockGap'], v)} />
                     <TransformControl label="Distância (Section Gap)" value={currentSlide?.options?.sectionGap ?? 48} min={0} max={300} step={4} onChange={(v) => updateSlideProperty(['options', 'sectionGap'], v)} />
                     <TransformControl label="Margens (Padding)" value={currentSlide?.options?.padding ?? 80} min={20} max={200} step={4} onChange={(v) => updateSlideProperty(['options', 'padding'], v)} />
                  </section>
                  <section className="space-y-6 pt-6 border-t border-white/5">
                    <PaletteColorSelector label="Background" value={currentSlide?.options?.background || '#0D0D0D'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'background'], v)} />
                    <PaletteColorSelector label="Accent" value={currentSlide?.options?.accent || '#EAB308'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'accent'], v)} />
                    <PaletteColorSelector label="Text" value={currentSlide?.options?.text || '#FFFFFF'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'text'], v)} />
                    <PaletteColorSelector label="Card Background" value={currentSlide?.options?.cardBg || '#EAB308'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'cardBg'], v)} />
                  </section>
                </div>
              )}
              {activeTab === 'FX' && (
                <div className="space-y-8 animate-in fade-in slide-in-from-left-4 duration-300">
                  <TransformControl label="Intensidade do Grão" value={currentSlide?.options?.postFX?.noiseAmount ?? 0} min={0} max={0.3} step={0.01} onChange={(v) => updateGlobalFX('noiseAmount', v)} />
                  <TransformControl label="Intensidade Clarity" value={currentSlide?.options?.postFX?.clarity ?? 0} min={0} max={1} step={0.01} onChange={(v) => updateGlobalFX('clarity', v)} />
                  <TransformControl label="Intensidade de Luz" value={currentSlide?.options?.postFX?.lightingIntensity ?? 0} min={0} max={1} step={0.01} onChange={(v) => updateGlobalFX('lightingIntensity', v)} />
                  <TransformControl label="Intensidade Vinheta" value={currentSlide?.options?.postFX?.vignette ?? 0} min={0} max={1} step={0.01} onChange={(v) => updateGlobalFX('vignette', v)} />
                </div>
              )}
              {activeTab === 'TEMPLATES' && (
                <div className="grid grid-cols-1 gap-2.5 animate-in fade-in duration-300">
                   {templates.map(tpl => (
                      <button key={tpl.name} onClick={() => handleTemplateSelect(tpl)} className={`w-full p-4 text-left border rounded-xl transition-all flex items-center gap-4 group ${currentSlide?.template === tpl.name ? 'border-emerald-500 bg-emerald-500/10' : 'border-white/5 bg-white/5 hover:border-emerald-500/20'}`}>
                        <Library size={20} className={currentSlide?.template === tpl.name ? 'text-emerald-500' : 'text-zinc-500'} />
                        <span className={`text-[10px] font-black uppercase ${currentSlide?.template === tpl.name ? 'text-emerald-400' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</span>
                      </button>
                    ))}
                </div>
              )}
              {activeTab === 'ASSETS' && (
                <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
                  {imageConfig?.url ? (
                    <div className="relative aspect-video rounded-xl overflow-hidden bg-black/40 border border-white/5">
                      <img src={imageConfig.url} className="w-full h-full object-contain" alt="Asset" />
                      <button onClick={() => updateSlideProperty(['image', 'url'], undefined)} className="absolute top-2 right-2 p-2 bg-red-500/80 rounded-lg"><Trash2 size={14}/></button>
                    </div>
                  ) : (
                    <div className="h-40 border-2 border-dashed border-white/10 rounded-xl flex items-center justify-center relative group cursor-pointer">
                      <PlusCircle className="text-zinc-600 group-hover:text-emerald-500" />
                      <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleImageUpload} />
                    </div>
                  )}
                  <div className="space-y-4 pt-4">
                    <TransformControl label="Escala" value={imageConfig?.scale ?? 1} min={0.1} max={5} step={0.1} onChange={(v) => updateSlideProperty(['image', 'scale'], v)} />
                    <TransformControl label="Eixo X" value={imageConfig?.x ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'x'], v)} />
                    <TransformControl label="Eixo Y" value={imageConfig?.y ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'y'], v)} />
                    <TransformControl label="Largura (Box)" value={imageConfig?.width ?? 500} min={100} max={1080} step={10} onChange={(v) => updateSlideProperty(['image', 'width'], v)} />
                  </div>
                </div>
              )}
              {activeTab === 'JSON' && (
                <div className="h-full flex flex-col gap-4 animate-in fade-in duration-300">
                  <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="flex-1 w-full bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-xl outline-none custom-scrollbar" spellCheck={false} />
                  <button onClick={handleRender} className="py-4 bg-white/5 border border-white/10 text-white font-black uppercase text-[10px] rounded-xl hover:bg-white/10">Validar JSON</button>
                </div>
              )}
            </div>
            <footer className="p-5 border-t border-white/5 bg-zinc-950">
              <button disabled={!carousel} onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="w-full py-4 bg-emerald-500 hover:bg-emerald-400 text-black font-black rounded-xl text-[10px] uppercase shadow-lg flex items-center justify-center gap-3"><Download size={16} strokeWidth={3} /> Exportar</button>
            </footer>
          </aside>

          <main className="flex-1 bg-[#18181b] relative flex flex-col">
            {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl animate-bounce"><AlertCircle size={18}/><span className="text-[11px] font-black uppercase">Erro de Sintaxe</span></div>}
            <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar p-10" onMouseUp={handleCanvasMouseUp}>
              <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-2xl shrink-0">
                {carousel?.slides?.[currentIndex] ? <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(block, blockIdx) => setEditingIconBlock({ block, index: blockIdx })} /> : <Loader2 className="animate-spin text-emerald-500" />}
              </div>
            </div>
            {carousel && (
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-8 bg-black/40 backdrop-blur-xl px-8 py-4 rounded-[32px] border border-white/5 shadow-2xl">
                 <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20} strokeWidth={3}/></button>
                 <div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-emerald-500 shadow-lg shadow-emerald-500/30' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}</div>
                 <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20} strokeWidth={3}/></button>
              </div>
            )}
          </main>
        </div>
      )}
    </div>
  );
};

export default App;

